import React, { useState, useEffect } from 'react';
import Navbar from './Navbar';
import Rainselector from './Rainselector';
import Mapview from './Mapview';
import WardCard from './wardcard';
import WardDetail from './Warddetail';

const Dashboard = ({ onNavigate }) => {
    const [selectedRain, setSelectedRain] = useState('real');
    const [wards, setWards] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedWard, setSelectedWard] = useState(null);

    useEffect(() => {
        fetchWards();
    }, [selectedRain]);

    const fetchWards = async () => {
        setLoading(true);
        try {
            const response = await fetch(`http://127.0.0.1:5000/predict?rain=${selectedRain}`);
            const data = await response.json();
            setWards(data);
        } catch (error) {
            console.error("Error fetching ward data:", error);
        } finally {
            setLoading(false);
        }
    };

    const filteredWards = wards.filter(w => 
        w.WardName.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div style={{ minHeight: '100vh', backgroundColor: 'var(--background)', color: 'var(--text-main)' }}>
            <Navbar onNavigate={onNavigate} />

            <div style={{ display: 'flex', paddingTop: '100px', height: 'calc(100vh - 100px)', gap: '20px', padding: '100px 20px 20px 20px', boxSizing: 'border-box' }}>

                {/* Left Sidebar: Control & List */}
                <div style={{ width: '350px', display: 'flex', flexDirection: 'column', gap: '20px', height: '100%' }}>

                    {/* Rain Selector */}
                    <div className="glass" style={{ padding: '20px' }}>
                        <h3 style={{ margin: '0 0 15px 0', fontSize: '1rem', color: 'var(--primary)', textTransform: 'uppercase', letterSpacing: '1px' }}>
                            Simulation Control
                        </h3>
                        <Rainselector selected={selectedRain} onChange={setSelectedRain} />
                    </div>

                    {/* Ward List */}
                    <div className="glass" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
                        <div style={{ padding: '20px', borderBottom: '1px solid var(--glass-border)' }}>
                            <input 
                                type="text" 
                                placeholder="Search wards..." 
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                style={{
                                    width: '100%',
                                    background: 'rgba(255,255,255,0.05)',
                                    border: '1px solid var(--glass-border)',
                                    padding: '10px 15px',
                                    borderRadius: '8px',
                                    color: 'white',
                                    outline: 'none'
                                }}
                            />
                        </div>
                        <div style={{ flex: 1, overflowY: 'auto', padding: '10px' }} className="custom-scrollbar">
                            {loading ? (
                                <div style={{ textAlign: 'center', padding: '20px', color: 'var(--text-muted)' }}>Loading intelligence...</div>
                            ) : (
                                filteredWards.map((ward, i) => (
                                    <WardCard key={i} ward={ward} onClick={setSelectedWard} />
                                ))
                            )}
                        </div>
                    </div>
                </div>

                {/* Main Content: Map */}
                <div style={{ flex: 1, height: '100%' }}>
                    <div className="glass" style={{ height: '100%', overflow: 'hidden', position: 'relative' }}>
                        <Mapview rain={selectedRain} />

                        {/* Map Overlay Stats */}
                        <div style={{ position: 'absolute', top: '20px', right: '20px', zIndex: 10, pointerEvents: 'none' }}>
                            <div className="glass" style={{ padding: '15px 25px', display: 'flex', gap: '30px' }}>
                                <div>
                                    <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase' }}>Active Scenario</div>
                                    <div style={{ fontSize: '1.2rem', fontWeight: '700', color: 'var(--primary)' }}>
                                        {selectedRain === 'real' ? '24h Real-time' : `${selectedRain}mm Simulation`}
                                    </div>
                                </div>
                                <div>
                                    <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase' }}>Avg. Prob</div>
                                    <div style={{ fontSize: '1.2rem', fontWeight: '700' }}>
                                        {(wards.reduce((acc, w) => acc + w.flood_probability, 0) / (wards.length || 1) * 100).toFixed(1)}%
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

            </div>

            {/* Modal Overlay */}
            {selectedWard && (
                <WardDetail ward={selectedWard} onClose={() => setSelectedWard(null)} />
            )}
        </div>
    );
};

export default Dashboard;
